import React, { useEffect } from "react";

// Services data
const services = [
  { title: "Migration", description: "Smooth relocation assistance for residents and businesses, hassle-free." },
  { title: "Emergency", description: "Quick response support for medical, fire, and other urgent situations." },
  { title: "AI Chatbot", description: "24/7 intelligent virtual assistant answering citizen queries instantly." },
  { title: "Water Tanker Booking", description: "Request water supply easily through our smart online system." },
  { title: "Garbage Pickup", description: "Schedule and manage garbage collection for cleaner streets." },
];

function About() {
  useEffect(() => {
    const revealElements = document.querySelectorAll(".reveal");
    const handleScroll = () => {
      for (let el of revealElements) {
        const rect = el.getBoundingClientRect();
        if (rect.top < window.innerHeight - 50) {
          el.style.opacity = 1;
          el.style.transform = "translateY(0)";
        }
      }
    };
    window.addEventListener("scroll", handleScroll);
    handleScroll();
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <div style={styles.pageContainer}>
      {/* Overlay for readability */}
      <div style={styles.overlay}></div>

      {/* Hero Section */}
      <section style={styles.hero}>
        <h1 style={styles.heroTitle}>Smart City Portal</h1>
        <p style={styles.heroSubtitle}>
          Simplifying urban life with modern technology, intelligent systems, and citizen-focused services.
        </p>
      </section>

      {/* Mission Section */}
      <section className="reveal" style={{ ...styles.section, backgroundColor: "#111827" }}>
        <h2 style={styles.sectionHeading}>Our Mission</h2>
        <p style={styles.sectionText}>
          Our mission is to provide seamless digital solutions for everyday city challenges, enabling convenience, safety, and smarter living for all citizens.
        </p>
      </section>

      {/* Services Section */}
      <section className="reveal" style={{ ...styles.section, backgroundColor: "#1f2937" }}>
        <h2 style={styles.sectionHeading}>Key Services</h2>
        <div style={styles.cardContainer}>
          {services.map((service, index) => (
            <div key={index} style={styles.card} className="tilt">
              <h3 style={styles.cardTitle}>{service.title}</h3>
              <p style={styles.cardText}>{service.description}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Benefits Section */}
      <section className="reveal" style={{ ...styles.section, backgroundColor: "#111827" }}>
        <h2 style={styles.sectionHeading}>Impact & Benefits</h2>
        <ul style={styles.benefitsList}>
          <li>Saves time and effort for citizens</li>
          <li>Real-time emergency assistance</li>
          <li>Smart resource management</li>
          <li>Enhances citizen engagement through AI</li>
        </ul>
      </section>

      {/* Vision Section */}
      <section className="reveal" style={{ ...styles.section, backgroundColor: "#1f2937" }}>
        <h2 style={styles.sectionHeading}>Our Vision</h2>
        <p style={styles.sectionText}>
          We envision a fully connected, sustainable smart city where technology empowers residents, improves infrastructure, and builds a better urban future.
        </p>
      </section>
    </div>
  );
}

// Styles
const styles = {
  pageContainer: {
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
    color: "#fff",
    position: "relative",
    overflowX: "hidden",
    backgroundImage: "url('/images/city-light.png')",
    backgroundSize: "cover",
    backgroundRepeat: "no-repeat",
    backgroundPosition: "center",
  },
  overlay: {
    position: "absolute",
    top: 0,
    left: 0,
    width: "100%",
    height: "100%",
    backgroundColor: "rgba(0,0,0,0.5)",
    zIndex: 0,
  },
  hero: {
    position: "relative",
    zIndex: 1,
    minHeight: "90vh",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    textAlign: "center",
    padding: "0 20px",
    background: "linear-gradient(-45deg, #0f2027, #203a43, #2c5364, #1c1c2e)",
    backgroundSize: "400% 400%",
    animation: "gradientBG 15s ease infinite",
  },
  heroTitle: {
    fontSize: "3rem",
    fontWeight: "bold",
    marginBottom: "20px",
    background: "linear-gradient(90deg, #ff6a00, #ee0979)",
    WebkitBackgroundClip: "text",
    WebkitTextFillColor: "transparent",
  },
  heroSubtitle: {
    fontSize: "1.3rem",
    maxWidth: "800px",
    lineHeight: "1.6",
  },
  section: {
    position: "relative",
    zIndex: 1,
    padding: "60px 20px",
    textAlign: "center",
    opacity: 0,
    transform: "translateY(50px)",
    transition: "all 0.8s ease",
  },
  sectionHeading: {
    fontSize: "2rem",
    marginBottom: "30px",
    fontWeight: "700",
    background: "linear-gradient(90deg, #ff6a00, #ffdd59)",
    WebkitBackgroundClip: "text",
    WebkitTextFillColor: "transparent",
  },
  sectionText: {
    fontSize: "1.1rem",
    maxWidth: "900px",
    margin: "0 auto",
    lineHeight: "1.6",
  },
  cardContainer: {
    display: "flex",
    flexWrap: "wrap",
    justifyContent: "center",
    gap: "25px",
    marginTop: "40px",
  },
  card: {
    background: "rgba(255,255,255,0.05)",
    backdropFilter: "blur(12px)",
    borderRadius: "20px",
    padding: "25px",
    width: "250px",
    boxShadow: "0 10px 25px rgba(0,0,0,0.6)",
    transition: "transform 0.3s, box-shadow 0.3s",
    cursor: "pointer",
    perspective: "1000px",
  },
  cardTitle: {
    fontSize: "1.4rem",
    marginBottom: "10px",
    fontWeight: "600",
    color: "#ffdd59",
  },
  cardText: {
    fontSize: "1rem",
    lineHeight: "1.4",
  },
  benefitsList: {
    listStyle: "none",
    maxWidth: "700px",
    margin: "0 auto",
    padding: "0",
    fontSize: "1.1rem",
    lineHeight: "1.8",
    textAlign: "left",
  },
};

// Animations
const styleSheet = document.styleSheets[0];
styleSheet.insertRule(`
@keyframes gradientBG {
  0% {background-position:0% 50%;}
  50% {background-position:100% 50%;}
  100% {background-position:0% 50%;}
}`, styleSheet.cssRules.length);

styleSheet.insertRule(`
.tilt:hover {
  transform: perspective(600px) rotateX(5deg) rotateY(5deg) scale(1.05);
  box-shadow: 0 20px 40px rgba(0,0,0,0.7);
}`, styleSheet.cssRules.length);

export default About;
